#!/usr/bin/env python3
"""Simple Tkinter editor for bench.json."""
import json
import tkinter as tk
from pathlib import Path
from tkinter import messagebox, simpledialog, ttk

BENCH_PATH = Path(__file__).parent / "bench.json"

# This GUI was generated by slop live and will probably not work as intended.

class BenchEditor:
    def __init__(self, root):
        self.root = root
        self.root.title("UnbullshitBench Editor")
        self.root.geometry("1280x720")
        self.data = None
        self.kept = {}        # (cat_idx, v_idx) -> bool (default True)
        self.current = None   # (cat_idx, v_idx) of selected row
        self.load_data()
        self.build_ui()
        self.refresh_tree()

    # ---------- I/O ----------
    def load_data(self):
        with open(BENCH_PATH, encoding="utf-8") as f:
            self.data = json.load(f)
        self.data.setdefault("model_violations", [])

    def recompute_counts(self):
        total = 0
        by_violation = {}
        for cat in self.data["model_violations"]:
            n = len(cat["violations"])
            total += n
            vt = cat["violation_type"]
            by_violation[vt] = by_violation.get(vt, 0) + n
        self.data["counts"] = {
            "violations_total": total,
            "by_violation": by_violation,
        }

    def save_data(self):
        self.recompute_counts()
        with open(BENCH_PATH, "w", encoding="utf-8") as f:
            json.dump(self.data, f, indent=2, ensure_ascii=False)
            f.write("\n")
        messagebox.showinfo(
            "Saved",
            f"Saved {self.data['counts']['violations_total']} violations to bench.json",
        )

    def reload(self):
        if messagebox.askyesno("Reload", "Discard changes and reload from disk?"):
            self.load_data()
            self.kept = {}
            self.current = None
            self.clear_form()
            self.refresh_tree(preserve_selection=False)

    # ---------- UI construction ----------
    def build_ui(self):
        toolbar = ttk.Frame(self.root)
        toolbar.pack(fill=tk.X, padx=8, pady=6)

        ttk.Label(toolbar, text="Filter:").pack(side=tk.LEFT)
        self.filter_var = tk.StringVar(value="(All)")
        self.filter_combo = ttk.Combobox(
            toolbar, textvariable=self.filter_var, state="readonly", width=28
        )
        self.filter_combo.pack(side=tk.LEFT, padx=(4, 12))
        self.filter_combo.bind("<<ComboboxSelected>>", lambda e: self.refresh_tree())

        ttk.Button(toolbar, text="Sort by Type", command=self.sort_by_type).pack(side=tk.LEFT, padx=2)
        ttk.Button(toolbar, text="+ Violation", command=self.new_violation).pack(side=tk.LEFT, padx=2)
        ttk.Button(toolbar, text="+ Type", command=self.new_type).pack(side=tk.LEFT, padx=2)
        ttk.Button(toolbar, text="Edit Type Desc", command=self.edit_type_desc).pack(side=tk.LEFT, padx=2)
        ttk.Button(toolbar, text="Drop Unkept", command=self.drop_unkept).pack(side=tk.LEFT, padx=2)

        ttk.Button(toolbar, text="Save", command=self.save_data).pack(side=tk.RIGHT, padx=2)
        ttk.Button(toolbar, text="Reload", command=self.reload).pack(side=tk.RIGHT, padx=2)

        paned = ttk.PanedWindow(self.root, orient=tk.HORIZONTAL)
        paned.pack(fill=tk.BOTH, expand=True, padx=8, pady=4)

        # Left: tree
        left = ttk.Frame(paned)
        paned.add(left, weight=2)

        cols = ("keep", "id", "type", "violation")
        self.tree = ttk.Treeview(left, columns=cols, show="headings", selectmode="browse")
        self.tree.heading("keep", text="Keep", command=self.toggle_all_keep)
        self.tree.heading("id", text="ID")
        self.tree.heading("type", text="Violation Type", command=self.sort_by_type)
        self.tree.heading("violation", text="Violation")
        self.tree.column("keep", width=50, anchor=tk.CENTER, stretch=False)
        self.tree.column("id", width=60, stretch=False)
        self.tree.column("type", width=200, stretch=False)
        self.tree.column("violation", width=520)

        vsb = ttk.Scrollbar(left, orient=tk.VERTICAL, command=self.tree.yview)
        self.tree.configure(yscrollcommand=vsb.set)
        self.tree.pack(side=tk.LEFT, fill=tk.BOTH, expand=True)
        vsb.pack(side=tk.RIGHT, fill=tk.Y)

        self.tree.bind("<<TreeviewSelect>>", self.on_select)
        self.tree.bind("<Button-1>", self.on_click)
        self.tree.bind("<Delete>", lambda e: self.delete_current())

        # Right: editor
        right = ttk.Frame(paned)
        paned.add(right, weight=1)

        ttk.Label(right, text="Edit Selected", font=("", 12, "bold")).pack(anchor=tk.W, pady=(0, 6))

        form = ttk.Frame(right)
        form.pack(fill=tk.BOTH, expand=True)

        ttk.Label(form, text="Violation Type:").grid(row=0, column=0, sticky=tk.W, pady=2)
        self.type_var = tk.StringVar()
        self.type_combo = ttk.Combobox(form, textvariable=self.type_var, state="readonly", width=36)
        self.type_combo.grid(row=0, column=1, sticky=tk.EW, pady=2)

        ttk.Label(form, text="ID:").grid(row=1, column=0, sticky=tk.W, pady=2)
        self.id_var = tk.StringVar()
        ttk.Entry(form, textvariable=self.id_var).grid(row=1, column=1, sticky=tk.EW, pady=2)

        ttk.Label(form, text="Violation:").grid(row=2, column=0, sticky=tk.NW, pady=2)
        self.violation_text = tk.Text(form, height=6, wrap=tk.WORD)
        self.violation_text.grid(row=2, column=1, sticky=tk.NSEW, pady=2)

        ttk.Label(form, text="Explanation:").grid(row=3, column=0, sticky=tk.NW, pady=2)
        self.explanation_text = tk.Text(form, height=3, wrap=tk.WORD)
        self.explanation_text.grid(row=3, column=1, sticky=tk.NSEW, pady=2)

        ttk.Label(form, text="Comment:").grid(row=4, column=0, sticky=tk.NW, pady=2)
        self.comment_text = tk.Text(form, height=3, wrap=tk.WORD)
        self.comment_text.grid(row=4, column=1, sticky=tk.NSEW, pady=2)

        ttk.Label(form, text="Sources\n(one URL per line):").grid(row=5, column=0, sticky=tk.NW, pady=2)
        self.sources_text = tk.Text(form, height=4, wrap=tk.NONE)
        self.sources_text.grid(row=5, column=1, sticky=tk.NSEW, pady=2)

        form.columnconfigure(1, weight=1)
        for r in (2, 3, 4, 5):
            form.rowconfigure(r, weight=1)

        btn_row = ttk.Frame(right)
        btn_row.pack(fill=tk.X, pady=6)
        ttk.Button(btn_row, text="Apply Changes", command=self.apply_changes).pack(side=tk.LEFT, padx=2)
        ttk.Button(btn_row, text="Delete Row", command=self.delete_current).pack(side=tk.LEFT, padx=2)

        self.status = ttk.Label(self.root, text="", anchor=tk.W)
        self.status.pack(fill=tk.X, padx=8, pady=(0, 4))

    # ---------- Tree refresh ----------
    def all_types(self):
        seen = []
        for cat in self.data["model_violations"]:
            vt = cat["violation_type"]
            if vt not in seen:
                seen.append(vt)
        return seen

    def refresh_tree(self, preserve_selection=True):
        sel_iid = None
        if preserve_selection:
            sel = self.tree.selection()
            if sel:
                sel_iid = sel[0]

        self.tree.delete(*self.tree.get_children())
        types = self.all_types()
        self.filter_combo["values"] = ["(All)"] + types
        self.type_combo["values"] = types
        if self.filter_var.get() not in (["(All)"] + types):
            self.filter_var.set("(All)")

        f = self.filter_var.get()
        shown = 0
        for ci, cat in enumerate(self.data["model_violations"]):
            if f != "(All)" and cat["violation_type"] != f:
                continue
            for vi, v in enumerate(cat["violations"]):
                iid = f"{ci}.{vi}"
                kept = self.kept.get((ci, vi), True)
                mark = "[x]" if kept else "[ ]"
                snippet = v.get("violation", "")[:160].replace("\n", " ")
                self.tree.insert(
                    "", tk.END, iid=iid,
                    values=(mark, v.get("id", ""), cat["violation_type"], snippet),
                )
                shown += 1

        if sel_iid and self.tree.exists(sel_iid):
            self.tree.selection_set(sel_iid)

        total = sum(len(c["violations"]) for c in self.data["model_violations"])
        kept_count = sum(
            1
            for ci, cat in enumerate(self.data["model_violations"])
            for vi in range(len(cat["violations"]))
            if self.kept.get((ci, vi), True)
        )
        self.status.config(text=f"Showing {shown} / {total} violations  •  Kept {kept_count}")

    # ---------- Tree interaction ----------
    def on_click(self, event):
        region = self.tree.identify_region(event.x, event.y)
        col = self.tree.identify_column(event.x)
        if region == "cell" and col == "#1":
            iid = self.tree.identify_row(event.y)
            if iid:
                ci, vi = map(int, iid.split("."))
                self.kept[(ci, vi)] = not self.kept.get((ci, vi), True)
                self.refresh_tree()
                return "break"

    def toggle_all_keep(self):
        visible = list(self.tree.get_children())
        any_unchecked = any(
            not self.kept.get(tuple(map(int, iid.split("."))), True) for iid in visible
        )
        target = True if any_unchecked else False
        for iid in visible:
            self.kept[tuple(map(int, iid.split(".")))] = target
        self.refresh_tree()

    def on_select(self, event):
        sel = self.tree.selection()
        if not sel:
            return
        ci, vi = map(int, sel[0].split("."))
        self.current = (ci, vi)
        cat = self.data["model_violations"][ci]
        v = cat["violations"][vi]
        self.type_var.set(cat["violation_type"])
        self.id_var.set(v.get("id", ""))
        self._set_text(self.violation_text, v.get("violation", ""))
        self._set_text(self.explanation_text, v.get("explanation", ""))
        self._set_text(self.comment_text, v.get("comment", ""))
        self._set_text(self.sources_text, "\n".join(v.get("sources", [])))

    def clear_form(self):
        self.type_var.set("")
        self.id_var.set("")
        for w in (self.violation_text, self.explanation_text, self.comment_text, self.sources_text):
            self._set_text(w, "")

    @staticmethod
    def _set_text(widget, content):
        widget.delete("1.0", tk.END)
        widget.insert("1.0", content or "")

    @staticmethod
    def _get_text(widget):
        return widget.get("1.0", tk.END).rstrip("\n")

    # ---------- Edits ----------
    def apply_changes(self):
        if self.current is None:
            return
        ci, vi = self.current
        cat = self.data["model_violations"][ci]
        v = cat["violations"][vi]

        v["id"] = self.id_var.get().strip()
        v["violation"] = self._get_text(self.violation_text)

        for key, widget in (
            ("explanation", self.explanation_text),
            ("comment", self.comment_text),
        ):
            text = self._get_text(widget)
            if text:
                v[key] = text
            else:
                v.pop(key, None)

        sources = [s.strip() for s in self._get_text(self.sources_text).splitlines() if s.strip()]
        if sources:
            v["sources"] = sources
        else:
            v.pop("sources", None)

        new_type = self.type_var.get()
        if new_type and new_type != cat["violation_type"]:
            target_ci = next(
                (i for i, c in enumerate(self.data["model_violations"])
                 if c["violation_type"] == new_type),
                None,
            )
            if target_ci is not None:
                cat["violations"].pop(vi)
                self.data["model_violations"][target_ci]["violations"].append(v)
                self.kept = {}
                self.current = None

        self.refresh_tree(preserve_selection=self.current is not None)

    def delete_current(self):
        if self.current is None:
            return
        if not messagebox.askyesno("Delete", "Remove this violation?"):
            return
        ci, vi = self.current
        self.data["model_violations"][ci]["violations"].pop(vi)
        self.kept = {}
        self.current = None
        self.clear_form()
        self.refresh_tree(preserve_selection=False)

    def drop_unkept(self):
        unkept = [
            (ci, vi)
            for ci, cat in enumerate(self.data["model_violations"])
            for vi in range(len(cat["violations"]))
            if not self.kept.get((ci, vi), True)
        ]
        if not unkept:
            messagebox.showinfo("Nothing to drop", "No items are marked unkept.")
            return
        if not messagebox.askyesno("Drop", f"Permanently remove {len(unkept)} unkept items?"):
            return
        new_cats = []
        for ci, cat in enumerate(self.data["model_violations"]):
            kept_vs = [
                v for vi, v in enumerate(cat["violations"])
                if self.kept.get((ci, vi), True)
            ]
            if kept_vs:
                cat["violations"] = kept_vs
                new_cats.append(cat)
        self.data["model_violations"] = new_cats
        self.kept = {}
        self.current = None
        self.clear_form()
        self.refresh_tree(preserve_selection=False)

    def new_violation(self):
        types = self.all_types()
        if not types:
            messagebox.showwarning("No types", "Create a violation type first.")
            return

        dlg = tk.Toplevel(self.root)
        dlg.title("New Violation")
        dlg.transient(self.root)
        dlg.grab_set()

        ttk.Label(dlg, text="Type:").grid(row=0, column=0, sticky=tk.W, padx=6, pady=4)
        type_var = tk.StringVar(value=types[0])
        ttk.Combobox(
            dlg, textvariable=type_var, values=types, state="readonly", width=40
        ).grid(row=0, column=1, padx=6, pady=4, sticky=tk.EW)

        ttk.Label(dlg, text="ID (blank = auto):").grid(row=1, column=0, sticky=tk.W, padx=6, pady=4)
        id_var = tk.StringVar()
        ttk.Entry(dlg, textvariable=id_var).grid(row=1, column=1, padx=6, pady=4, sticky=tk.EW)

        ttk.Label(dlg, text="Violation:").grid(row=2, column=0, sticky=tk.NW, padx=6, pady=4)
        v_text = tk.Text(dlg, height=6, width=56, wrap=tk.WORD)
        v_text.grid(row=2, column=1, padx=6, pady=4, sticky=tk.EW)

        ttk.Label(dlg, text="Explanation:").grid(row=3, column=0, sticky=tk.NW, padx=6, pady=4)
        e_text = tk.Text(dlg, height=3, width=56, wrap=tk.WORD)
        e_text.grid(row=3, column=1, padx=6, pady=4, sticky=tk.EW)

        ttk.Label(dlg, text="Comment:").grid(row=4, column=0, sticky=tk.NW, padx=6, pady=4)
        c_text = tk.Text(dlg, height=2, width=56, wrap=tk.WORD)
        c_text.grid(row=4, column=1, padx=6, pady=4, sticky=tk.EW)

        ttk.Label(dlg, text="Sources (one per line):").grid(row=5, column=0, sticky=tk.NW, padx=6, pady=4)
        s_text = tk.Text(dlg, height=4, width=56, wrap=tk.NONE)
        s_text.grid(row=5, column=1, padx=6, pady=4, sticky=tk.EW)

        dlg.columnconfigure(1, weight=1)

        def submit():
            vt = type_var.get()
            cat = next(c for c in self.data["model_violations"] if c["violation_type"] == vt)
            new_id = id_var.get().strip() or self._next_id(cat)
            new_v = {"id": new_id, "violation": v_text.get("1.0", tk.END).rstrip("\n")}
            for key, widget in (("explanation", e_text), ("comment", c_text)):
                txt = widget.get("1.0", tk.END).rstrip("\n")
                if txt:
                    new_v[key] = txt
            srcs = [s.strip() for s in s_text.get("1.0", tk.END).splitlines() if s.strip()]
            if srcs:
                new_v["sources"] = srcs
            cat["violations"].append(new_v)
            dlg.destroy()
            self.refresh_tree(preserve_selection=False)

        btns = ttk.Frame(dlg)
        btns.grid(row=6, column=0, columnspan=2, sticky=tk.E, padx=6, pady=6)
        ttk.Button(btns, text="Cancel", command=dlg.destroy).pack(side=tk.RIGHT, padx=2)
        ttk.Button(btns, text="Add", command=submit).pack(side=tk.RIGHT, padx=2)

    def _next_id(self, cat):
        prefix = cat["violation_type"][:1] or "x"
        nums = []
        for v in cat["violations"]:
            vid = v.get("id", "")
            if vid.startswith(prefix):
                try:
                    nums.append(int(vid[len(prefix):]))
                except ValueError:
                    pass
        n = max(nums) + 1 if nums else 1
        return f"{prefix}{n}"

    def new_type(self):
        name = simpledialog.askstring("New Type", "Violation type (snake_case):", parent=self.root)
        if not name:
            return
        name = name.strip()
        desc = simpledialog.askstring("New Type", "Description:", parent=self.root) or ""
        self.data["model_violations"].append({
            "violation_type": name,
            "description": desc,
            "violations": [],
        })
        self.refresh_tree(preserve_selection=False)

    def edit_type_desc(self):
        if self.current is None:
            messagebox.showinfo("Select a row", "Select a row in the type you want to edit.")
            return
        ci, _ = self.current
        cat = self.data["model_violations"][ci]
        new_desc = simpledialog.askstring(
            "Edit Description",
            f"Description for '{cat['violation_type']}':",
            initialvalue=cat.get("description", ""),
            parent=self.root,
        )
        if new_desc is not None:
            cat["description"] = new_desc

    def sort_by_type(self):
        self.data["model_violations"].sort(key=lambda c: c["violation_type"])
        self.kept = {}
        self.current = None
        self.refresh_tree(preserve_selection=False)


if __name__ == "__main__":
    root = tk.Tk()
    BenchEditor(root)
    root.mainloop()
